def get_stroke_count(char):
    """Get stroke count for a character"""
    return STROKE_COUNT.get(char, '?')


def get_radical_info(char):
    """Get radical info: returns (radical, name, meaning) or None"""
    return RADICAL_INFO.get(char)


def get_common_words(char):
    """Get common words containing this character"""
    return COMMON_WORDS.get(char, [])


def get_example_sentences(char):
    """Get example sentences for this character"""
    return EXAMPLE_SENTENCES.get(char, [])
